 62→func (a *Agent) querySessionID(cwd string) (string, error) {
 63→	db, err := kiroCLIDataDBPath()
 64→	if err != nil {
 65→		return "", err
 66→	}
 67→	if _, err := os.Stat(db); err != nil {
 68→		return "", fmt.Errorf("kiro database not found at %s: %w", db, err)
 69→	}
 70→
 71→	query := fmt.Sprintf(
 72→		"SELECT json_extract(value, '$.conversation_id') FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
 73→		escapeSQLString(cwd),
 74→	)
 75→
 76→	out, err := runSQLiteCommand("-json", db, query)
 77→	if err != nil {
 78→		return "", fmt.Errorf("sqlite3 query failed: %w", err)
 79→	}
 80→
 81→	result := strings.TrimSpace(string(out))
 82→	if result == "" || result == "[]" {
 83→		return "", nil
 84→	}
 85→
 86→	var rows []map[string]string
 87→	if err := json.Unmarshal([]byte(result), &rows); err != nil {
 88→		return "", fmt.Errorf("failed to parse sqlite3 output: %w", err)
 89→	}
 90→	if len(rows) == 0 {
 91→		return "", nil
 92→	}
 93→	for _, value := range rows[0] {
 94→		return value, nil
 95→	}
 96→	return "", nil
 97→}
