173→func (a *Agent) captureTranscriptForStop(cwd string, sessionID string) string {
174→	if sessionRef, err := a.ensureCachedTranscript(cwd, sessionID); err == nil && sessionRef != "" {
175→		return sessionRef
176→	}
177→	if sessionRef, err := a.ensureIDETranscript(cwd, sessionID); err == nil && sessionRef != "" {
178→		return sessionRef
179→	}
180→	return a.createPlaceholderTranscript(cwd, sessionID)
181→}
