209→func kiroDataDir() (string, error) {
210→	home, err := os.UserHomeDir()
211→	if err != nil {
212→		return "", fmt.Errorf("failed to get home directory: %w", err)
213→	}
214→	switch runtime.GOOS {
215→	case "darwin":
216→		return filepath.Join(home, "Library", "Application Support"), nil
217→	default:
218→		return filepath.Join(home, ".local", "share"), nil
219→	}
