249→func (a *Agent) GetTranscriptPosition(path string) (int, error) {
250→	transcript, err := readAndParseTranscript(path)
251→	if errors.Is(err, os.ErrNotExist) {
252→		return 0, nil
253→	}
254→	if err != nil {
255→		return 0, err
256→	}
257→	return len(transcript.History), nil
258→}
