260→func (a *Agent) ExtractModifiedFiles(path string, offset int) ([]string, int, error) {
261→	transcript, err := readAndParseTranscript(path)
262→	if errors.Is(err, os.ErrNotExist) {
263→		return nil, 0, nil
264→	}
265→	if err != nil {
266→		return nil, 0, err
267→	}
268→
269→	totalEntries := len(transcript.History)
270→	if offset >= totalEntries {
271→		return nil, totalEntries, nil
272→	}
273→
274→	return extractModifiedFilesFromHistory(transcript.History[offset:]), totalEntries, nil
275→}
