277→func (a *Agent) ExtractPrompts(path string, offset int) ([]string, error) {
278→	transcript, err := readAndParseTranscript(path)
279→	if errors.Is(err, os.ErrNotExist) {
280→		return nil, nil
281→	}
282→	if err != nil {
283→		return nil, err
284→	}
285→
286→	var prompts []string
287→	for i := offset; i < len(transcript.History); i++ {
288→		if prompt := extractUserPrompt(transcript.History[i].User.Content); prompt != "" {
289→			prompts = append(prompts, prompt)
290→		}
291→	}
292→	return prompts, nil
293→}
