295→func (a *Agent) ExtractSummary(path string) (string, bool, error) {
296→	transcript, err := readAndParseTranscript(path)
297→	if errors.Is(err, os.ErrNotExist) {
298→		return "", false, nil
299→	}
300→	if err != nil {
301→		return "", false, err
302→	}
303→
304→	summary := extractLastAssistantResponse(transcript.History)
305→	return summary, summary != "", nil
306→}
