308→func readAndParseTranscript(path string) (*kiroTranscript, error) {
309→	data, err := os.ReadFile(path)
310→	if err != nil {
311→		return nil, err
312→	}
313→	return parseTranscript(data)
314→}
315→
316→func parseTranscript(data []byte) (*kiroTranscript, error) {
317→	if len(data) == 0 {
318→		return &kiroTranscript{}, nil
319→	}
320→
321→	var transcript kiroTranscript
322→	if err := json.Unmarshal(data, &transcript); err != nil {
323→		return nil, fmt.Errorf("failed to parse kiro transcript: %w", err)
324→	}
325→	if isCLITranscript(&transcript) {
326→		return &transcript, nil
327→	}
328→
329→	if converted := tryParseIDETranscript(data); converted != nil {
330→		return converted, nil
331→	}
332→
333→	return &transcript, nil
334→}
335→
336→func isCLITranscript(transcript *kiroTranscript) bool {
337→	if len(transcript.History) == 0 {
338→		return false
339→	}
340→	return len(transcript.History[0].User.Content) > 0 || len(transcript.History[0].Assistant) > 0
341→}
342→
343→func tryParseIDETranscript(data []byte) *kiroTranscript {
344→	var ide kiroIDETranscript
345→	if err := json.Unmarshal(data, &ide); err != nil {
346→		return nil
347→	}
348→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
349→		return nil
350→	}
351→	return convertIDETranscript(&ide)
352→}
353→
354→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
355→	transcript := &kiroTranscript{}
356→
357→	var pendingUser *kiroIDEHistoryEntry
358→	for i := range ide.History {
359→		entry := &ide.History[i]
360→		switch entry.Message.Role {
361→		case "user":
362→			if pendingUser != nil {
363→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
364→			}
365→			pendingUser = entry
366→		case "assistant":
367→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
368→			pendingUser = nil
369→		}
370→	}
371→
372→	if pendingUser != nil {
373→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
374→	}
375→
376→	return transcript
377→}
378→
379→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
380→	entry := kiroHistoryEntry{}
381→
382→	if user != nil {
383→		prompt := extractIDEText(user.Message.Content, true)
384→		if prompt != "" {
385→			content, err := json.Marshal(kiroPromptContent{
386→				Prompt: struct {
387→					Prompt string `json:"prompt"`
388→				}{Prompt: prompt},
389→			})
390→			if err == nil {
391→				entry.User.Content = content
392→			}
393→		} else {
394→			entry.User.Content = user.Message.Content
395→		}
396→	}
397→
398→	if assistant != nil {
399→		text := extractIDEText(assistant.Message.Content, false)
400→		if text != "" {
401→			content, err := json.Marshal(kiroResponseContent{
402→				Response: kiroResponsePayload{Content: text},
403→			})
404→			if err == nil {
405→				entry.Assistant = content
406→			}
407→		} else {
408→			entry.Assistant = assistant.Message.Content
409→		}
410→	}
411→
412→	return entry
413→}
414→
415→// extractIDEText extracts text from a json.RawMessage that may be either a
416→// plain string or an array of content blocks. When blocksFirst is true, it
417→// tries to parse as blocks before falling back to a plain string (user
418→// messages); otherwise it tries plain string first (assistant messages).
419→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
420→	if len(content) == 0 {
421→		return ""
422→	}
423→
424→	tryBlocks := func() string {
425→		var blocks []kiroIDEContentBlock
426→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
427→			for _, block := range blocks {
428→				if block.Type == "text" && block.Text != "" {
429→					return block.Text
430→				}
431→			}
432→		}
433→		return ""
434→	}
435→
436→	tryString := func() string {
437→		var text string
438→		if err := json.Unmarshal(content, &text); err == nil {
439→			return text
440→		}
441→		return ""
442→	}
443→
444→	if blocksFirst {
445→		if s := tryBlocks(); s != "" {
446→			return s
447→		}
448→		return tryString()
449→	}
450→	if s := tryString(); s != "" {
451→		return s
452→	}
453→	return tryBlocks()
454→}
455→
456→func extractUserPrompt(content json.RawMessage) string {
457→	if len(content) == 0 {
458→		return ""
459→	}
460→
461→	var promptContent kiroPromptContent
462→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
463→		return promptContent.Prompt.Prompt
464→	}
465→	return ""
466→}
467→
468→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
469→	seen := make(map[string]bool)
470→	var files []string
471→
472→	for i := range entries {
473→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
474→			if path == "" || seen[path] {
475→				continue
476→			}
477→			seen[path] = true
478→			files = append(files, path)
479→		}
480→	}
481→
482→	return files
483→}
484→
485→func extractFilesFromAssistant(raw json.RawMessage) []string {
486→	if len(raw) == 0 {
487→		return nil
488→	}
489→
490→	var toolUseContent kiroToolUseContent
491→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
492→		return nil
493→	}
494→
495→	var paths []string
496→	for _, call := range toolUseContent.ToolUse.ToolUses {
497→		if !isFileModificationTool(call.Name) {
498→			continue
499→		}
500→		if path := extractFilePath(call.Args); path != "" {
501→			paths = append(paths, path)
502→		}
503→	}
504→	return paths
505→}
506→
507→func isFileModificationTool(name string) bool {
508→	_, ok := kiroFileModificationTools[name]
509→	return ok
510→}
511→
512→func extractFilePath(args json.RawMessage) string {
513→	if len(args) == 0 {
514→		return ""
515→	}
516→
517→	var fields map[string]json.RawMessage
518→	if err := json.Unmarshal(args, &fields); err != nil {
519→		return ""
520→	}
521→
522→	for _, key := range []string{"path", "file_path", "filename"} {
523→		raw, ok := fields[key]
524→		if !ok {
525→			continue
526→		}
527→		var path string
528→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
529→			return path
530→		}
531→	}
532→	return ""
533→}
534→
535→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
536→	for i := len(entries) - 1; i >= 0; i-- {
537→		if len(entries[i].Assistant) == 0 {
538→			continue
539→		}
540→
541→		var responseContent kiroResponseContent
542→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
543→			return responseContent.Response.Content
544→		}
545→	}
546→	return ""
547→}
